import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o,c as n,a2 as p}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Automatické tagování","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Other/auto-tagging.md","filePath":"cs-CZ/Other/auto-tagging.md","lastUpdated":1781962217000}'),d={name:"cs-CZ/Other/auto-tagging.md"};function i(s,a,r,c,l,u){return o(),n("div",null,[...a[0]||(a[0]=[p('<h1 id="automaticke-tagovani" tabindex="-1">Automatické tagování <a class="header-anchor" href="#automaticke-tagovani" aria-label="Permalink to &quot;Automatické tagování&quot;">​</a></h1><p>Automatické tagování se nastavuje v:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>Automaticky generuje tagy obrázků. Hodí se pro vyhledávání, filtrování Random Image API, filtrování veřejné galerie a řízení přístupu podle věkového ratingu.</p><h2 id="co-automaticke-tagovani-umi" tabindex="-1">Co automatické tagování umí <a class="header-anchor" href="#co-automaticke-tagovani-umi" aria-label="Permalink to &quot;Co automatické tagování umí&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funkce</th><th>Popis</th></tr></thead><tbody><tr><td>Generovat tagy obsahu</td><td>Přidává tagy pro osoby, scény, objekty, výtvarný styl a podobný vizuální obsah.</td></tr><tr><td>Generovat tagy postav</td><td>Užitečné pro anime obrázky a ilustrace.</td></tr><tr><td>Přidat tagy orientace</td><td>Přidá <code>landscape</code>, <code>portrait</code> nebo <code>square</code>.</td></tr><tr><td>Přidat rating obrázku</td><td>Ukládá výsledky <code>G/S/Q/E</code> pro obecný, citlivý, sporný nebo explicitní obsah.</td></tr><tr><td>Automatické tagování při uploadu</td><td>Nově nahrané obrázky automaticky projdou tagovacím tokem.</td></tr><tr><td>Hromadné tagování</td><td>Přidá tagy starším obrázkům ve všech adresářích nebo vybraných adresářích.</td></tr></tbody></table><h2 id="co-pripravit-predem" tabindex="-1">Co připravit předem <a class="header-anchor" href="#co-pripravit-predem" aria-label="Permalink to &quot;Co připravit předem&quot;">​</a></h2><p>Připravte alespoň jeden dostupný Hugging Face Space URL.</p><p>Doporučený postup je zduplikovat SmilingWolfův Space <code>wd-tagger</code> do vlastního účtu Hugging Face:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Veřejný Space můžete dočasně použít, ale veřejné Spaces sdílí mnoho uživatelů a mohou mít frontu, zpomalovat se nebo být nedostupné. Vlastní zduplikovaný Space je pro dlouhodobé automatické tagování stabilnější.</p><h2 id="duplikovani-smilingwolf-space" tabindex="-1">Duplikování SmilingWolf Space <a class="header-anchor" href="#duplikovani-smilingwolf-space" aria-label="Permalink to &quot;Duplikování SmilingWolf Space&quot;">​</a></h2><ol><li>Přihlaste se do Hugging Face.</li><li>Otevřete <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+t+`" alt="Veřejný Space SmilingWolf" loading="lazy"></p><ol start="3"><li>Klikněte vpravo nahoře na menu se třemi tečkami.</li><li>Vyberte <code>Duplicate this Space</code>.</li><li>Nechte výchozí název Space nebo zvolte vlastní, například <code>wd-tagger</code>.</li><li>Viditelnost nastavte na <code>Public</code>. Veřejné Spaces se ImgBed volají jednodušeji.</li><li>Nejprve ponechte výchozí bezplatný hardware. Upgrade řešte až tehdy, když je fronta zjevný problém.</li><li>Vytvořte Space a počkejte na dokončení buildu.</li></ol><p>Po dokončení buildu otevřete stránku svého Space. URL obvykle vypadá takto:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Zkopírujte URL z prohlížeče a vložte ho do <code>Space URLs</code> v ImgBed.</p><h2 id="vyplneni-vice-space-url" tabindex="-1">Vyplnění více Space URL <a class="header-anchor" href="#vyplneni-vice-space-url" aria-label="Permalink to &quot;Vyplnění více Space URL&quot;">​</a></h2><p>Zadávejte jeden Space URL na řádek.</p><p>Příklady:</p><table tabindex="0"><thead><tr><th>Hodnota</th><th>Popis</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>Veřejný Space SmilingWolf. Vhodné pro dočasné testy.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>URL stránky zkopírovaného Space.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Váš vlastní zduplikovaný Space.</td></tr></tbody></table><p>Můžete zadat více URL. ImgBed používá více Spaces společně, což může zlepšit rychlost.</p><p>Pokud je jeden Space dočasně nedostupný, ostatní mohou pokračovat ve zpracování.</p><h2 id="nastaveni" tabindex="-1">Nastavení <a class="header-anchor" href="#nastaveni" aria-label="Permalink to &quot;Nastavení&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Volba</th><th>Doporučení</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Zadejte připravené Space URL. Použijte alespoň jeden.</td></tr><tr><td>Cílový adresář</td><td>Nechte prázdné pro všechny adresáře. Adresář vyberte jen tehdy, když chcete zpracovat konkrétní složku.</td></tr><tr><td>Model rozpoznávání</td><td>Ve výchozím stavu ponechte <code>wd-swinv2-tagger-v3</code>.</td></tr><tr><td>Práh obecných tagů</td><td>Výchozí hodnota funguje pro většinu obrázků. Nižší hodnota vytvoří víc tagů, vyšší méně.</td></tr><tr><td>Práh tagů postav</td><td>Výchozí hodnota je opatrná a pomáhá omezit chybné tagy postav.</td></tr><tr><td>Automatický práh <code>MCut</code></td><td>Na začátku nechte vypnuté. Zapněte, když chcete, aby model sám rozhodoval o počtu tagů.</td></tr><tr><td>Automaticky tagovat při uploadu</td><td>Zapněte, pokud mají nové obrázky automaticky dostávat tagy.</td></tr><tr><td>Spustit tagování</td><td>Ruční hromadné tagování starších obrázků.</td></tr></tbody></table><h2 id="doporucene-pocatecni-hodnoty" tabindex="-1">Doporučené počáteční hodnoty <a class="header-anchor" href="#doporucene-pocatecni-hodnoty" aria-label="Permalink to &quot;Doporučené počáteční hodnoty&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Volba</th><th>Doporučená hodnota</th></tr></thead><tbody><tr><td>Model rozpoznávání</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>Práh obecných tagů</td><td><code>0.35</code></td></tr><tr><td>Práh tagů postav</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Na začátku vypnuto</td></tr><tr><td>Automatické tagování při uploadu</td><td>Zapnout podle potřeby</td></tr></tbody></table><p>Pokud je tagů příliš mnoho, lehce zvyšte obecný práh.</p><p>Pokud je tagů příliš málo, lehce ho snižte.</p><h2 id="hromadne-tagovani" tabindex="-1">Hromadné tagování <a class="header-anchor" href="#hromadne-tagovani" aria-label="Permalink to &quot;Hromadné tagování&quot;">​</a></h2><ol><li>Vyplňte <code>Space URLs</code>.</li><li>Vyberte cílový adresář.</li><li>Klikněte na spuštění tagování.</li><li>Počkejte na dokončení.</li></ol><p>Pokud je cílový adresář prázdný, ImgBed zpracuje všechny adresáře.</p><p>Hromadné tagování je nejlepší pro staré obrázky. Pro nové obrázky zapněte automatické tagování při uploadu, abyste ho nemuseli spouštět ručně.</p><h2 id="automaticke-tagovani-pri-uploadu" tabindex="-1">Automatické tagování při uploadu <a class="header-anchor" href="#automaticke-tagovani-pri-uploadu" aria-label="Permalink to &quot;Automatické tagování při uploadu&quot;">​</a></h2><p>Po zapnutí se u nově nahraných obrázků automaticky volají nastavené <code>Space URLs</code>.</p><p>Je to vhodné pro dlouhodobé používání.</p><p>Pokud má Space frontu, samotný upload může skončit dřív a tagování pokračuje potom.</p><h2 id="ktere-obrazky-se-zpracuji" tabindex="-1">Které obrázky se zpracují <a class="header-anchor" href="#ktere-obrazky-se-zpracuji" aria-label="Permalink to &quot;Které obrázky se zpracují&quot;">​</a></h2><p>Automatické tagování zpracovává hlavně obrazové soubory.</p><p>Obrázky, které už mají kompletní tagy, orientaci, rating, šířku a výšku, se přeskočí, aby se zbytečně nevolal Space.</p><p>ImgBed doplňuje jen chybějící informace, kdykoli je to možné. Pokud chybí například jen orientace, pokusí se ji doplnit bez celého toku tagování obsahu.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="proc-duplikovat-vlastni-space" tabindex="-1">Proč duplikovat vlastní Space? <a class="header-anchor" href="#proc-duplikovat-vlastni-space" aria-label="Permalink to &quot;Proč duplikovat vlastní Space?&quot;">​</a></h3><p>Veřejné Spaces sdílí mnoho uživatelů. Váš zduplikovaný Space používá hlavně váš web ImgBed, takže je obvykle rychlejší a spolehlivější.</p><h3 id="space-se-porad-spousti" tabindex="-1">Space se pořád spouští <a class="header-anchor" href="#space-se-porad-spousti" aria-label="Permalink to &quot;Space se pořád spouští&quot;">​</a></h3><p>Po prvním vytvoření nebo po dlouhé nečinnosti může Space potřebovat čas na start.</p><p>Nejprve otevřete stránku Space. Jakmile normálně rozpozná obrázek, vraťte se do ImgBed a spusťte tagování.</p><h3 id="jak-zkopirovat-space-url" tabindex="-1">Jak zkopírovat Space URL? <a class="header-anchor" href="#jak-zkopirovat-space-url" aria-label="Permalink to &quot;Jak zkopírovat Space URL?&quot;">​</a></h3><p>Otevřete stránku Hugging Face Space a zkopírujte adresu z prohlížeče.</p><p>Příklady:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="mohu-pridat-vice-spaces" tabindex="-1">Mohu přidat více Spaces? <a class="header-anchor" href="#mohu-pridat-vice-spaces" aria-label="Permalink to &quot;Mohu přidat více Spaces?&quot;">​</a></h3><p>Ano. Zadejte jeden Space URL na řádek.</p><p>Více Spaces zpracovává obrázky společně a hodí se při velkém množství obrázků.</p><h3 id="proc-jsou-tagy-anglicky" tabindex="-1">Proč jsou tagy anglicky? <a class="header-anchor" href="#proc-jsou-tagy-anglicky" aria-label="Permalink to &quot;Proč jsou tagy anglicky?&quot;">​</a></h3><p>Modely SmilingWolf vracejí tagy v angličtině. Je to očekávané.</p><p>Tagy slouží hlavně pro vyhledávání, filtrování, Random Image API a filtry veřejné galerie.</p><h3 id="k-cemu-jsou-rating-tagy" tabindex="-1">K čemu jsou rating tagy? <a class="header-anchor" href="#k-cemu-jsou-rating-tagy" aria-label="Permalink to &quot;K čemu jsou rating tagy?&quot;">​</a></h3><p>Výsledky ratingu spolupracují s režimem přístupu v Bezpečnostních nastaveních.</p><p>Když je například přístup návštěvníků omezený podle věku, veřejné procházení a funkce náhodných obrázků filtrují obrázky podle těchto pravidel.</p><h2 id="rychly-postup" tabindex="-1">Rychlý postup <a class="header-anchor" href="#rychly-postup" aria-label="Permalink to &quot;Rychlý postup&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Přihlaste se do Hugging Face</span></span>
<span class="line"><span>-&gt; Otevřete SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Počkejte na build Space</span></span>
<span class="line"><span>-&gt; Zkopírujte URL svého Space</span></span>
<span class="line"><span>-&gt; Vyplňte Space URLs v ImgBed</span></span>
<span class="line"><span>-&gt; Vyberte model a prahy</span></span>
<span class="line"><span>-&gt; Spusťte tagování nebo zapněte automatické tagování při uploadu</span></span></code></pre></div>`,63)])])}const k=e(d,[["render",i]]);export{g as __pageData,k as default};
